import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../hooks/usecart';
import { ChevronLeft, MapPin, AlertTriangle, ShieldCheck, Loader2 } from 'lucide-react';

const CheckoutPage = () => {
  const navigate = useNavigate();
  const { items = [] } = useCart();

  const validItems = items.filter(item => item && item.productId && String(item.productId) !== 'undefined');

  useEffect(() => {
    if (validItems.length === 0) {
      navigate('/cart');
    }
  }, [validItems, navigate]);

  // ========================================================
  // 🚀 FORM STATES
  // ========================================================
  const [isBillingSame, setIsBillingSame] = useState(true);

  const [shipping, setShipping] = useState({
    fullName: '', phone: '', address1: '', address2: '', pincode: '', city: '', state: ''
  });

  const [billing, setBilling] = useState({
    fullName: '', email: '', phone: '', pincode: '', city: '', state: '', address1: '', address2: '', landmark: ''
  });

  // Validation Modal State
  const [errors, setErrors] = useState({});
  const [showModal, setShowModal] = useState(false);
  const [modalMessage, setModalMessage] = useState('');

  const [fetchingPin, setFetchingPin] = useState({ shipping: false, billing: false });

  // ========================================================
  // 🚀 API: AUTO-FETCH PINCODE
  // ========================================================
  const fetchLocation = async (pin, type) => {
    if (pin.length !== 6) return;
    setFetchingPin(prev => ({ ...prev, [type]: true }));

    try {
      const response = await fetch(`https://api.postalpincode.in/pincode/${pin}`);
      const data = await response.json();

      if (data && data[0] && data[0].Status === 'Success' && data[0].PostOffice?.length > 0) {
        const po = data[0].PostOffice[0];
        const fetchedCity = po.District || po.Block || po.Region || '';
        const fetchedState = po.State || '';

        if (type === 'shipping') {
          setShipping(prev => ({ ...prev, city: fetchedCity, state: fetchedState }));
        } else {
          setBilling(prev => ({ ...prev, city: fetchedCity, state: fetchedState }));
        }
        setErrors(prev => ({ ...prev, [`shipping_city`]: false, [`shipping_state`]: false, [`shipping_pincode`]: false }));
      }
    } catch (error) {
      console.error("Error fetching pincode:", error);
    } finally {
      setFetchingPin(prev => ({ ...prev, [type]: false }));
    }
  };

  useEffect(() => {
    const pin = shipping.pincode.replace(/\D/g, '');
    const timeoutId = setTimeout(() => { if (pin.length === 6) fetchLocation(pin, 'shipping'); }, 400);
    return () => clearTimeout(timeoutId);
  }, [shipping.pincode]);

  useEffect(() => {
    const pin = billing.pincode.replace(/\D/g, '');
    const timeoutId = setTimeout(() => { if (pin.length === 6) fetchLocation(pin, 'billing'); }, 400);
    return () => clearTimeout(timeoutId);
  }, [billing.pincode]);

  // ========================================================
  // 🚀 MATH CALCULATIONS (Matches Cart Structure)
  // ========================================================
  const totalItems = validItems.reduce((acc, item) => acc + (Number(item.quantity) || 1), 0);

  let totalDiscountedPrice = 0;
  let totalMrp = 0;

  validItems.forEach(item => {
    const qty = Number(item.quantity) || 1;
    const price = Number(item.price) || 0;
    const mrp = Number(item.compare_price || item.mrp) || Math.round(price * 1.25);
    totalDiscountedPrice += (price * qty);
    totalMrp += (mrp * qty);
  });

  const baseDiscount = Math.max(0, totalMrp - totalDiscountedPrice);
  const gst = Math.round(totalDiscountedPrice * 0.18);
  const finalPayable = totalDiscountedPrice + gst;

  // Handlers
  const handleShippingChange = (e) => {
    const { name, value } = e.target;
    if (name === 'pincode' && value && !/^\d*$/.test(value)) return;
    setShipping(prev => ({ ...prev, [name]: value }));
    if (errors[`shipping_${name}`]) setErrors(prev => ({ ...prev, [`shipping_${name}`]: false }));
  };

  const handleBillingChange = (e) => {
    const { name, value } = e.target;
    if (name === 'pincode' && value && !/^\d*$/.test(value)) return;
    setBilling(prev => ({ ...prev, [name]: value }));
    if (errors[`billing_${name}`]) setErrors(prev => ({ ...prev, [`billing_${name}`]: false }));
  };

  const handleContinuePayment = () => {
    let hasError = false;
    const newErrors = {};

    // 1. Validate Shipping
    const reqShipping = ['fullName', 'phone', 'address1', 'pincode', 'city', 'state'];
    reqShipping.forEach(field => {
      if (!shipping[field].trim()) { newErrors[`shipping_${field}`] = true; hasError = true; }
    });

    if (shipping.phone && shipping.phone.replace(/\D/g, '').length < 10) {
      newErrors.shipping_phone = true; hasError = true;
    }
    if (shipping.pincode && shipping.pincode.replace(/\D/g, '').length !== 6) {
      newErrors.shipping_pincode = true; hasError = true;
    }

    if (hasError) {
      setErrors(newErrors);
      setModalMessage('Please fill in all required shipping details to proceed with your order.');
      setShowModal(true);
      return;
    }

    console.log("Proceeding to payment:", { shipping, billing: isBillingSame ? shipping : billing });
    alert("Validation Passed! Proceeding to Payment Gateway.");
  };

  // CLEAN INPUT CLASS (No ghost lines, no shadows)
  const getInputClass = (isError) => `
    w-full text-sm rounded-xl px-4 py-3.5 outline-none focus:outline-none focus:ring-0 transition-colors placeholder:text-gray-400
    ${isError
      ? 'bg-[#fef2f2] border border-[#f87171] text-gray-900'
      : 'bg-white border border-gray-200 focus:border-[#f97316] text-gray-900'
    }
  `;

  return (
    <div className="bg-[#f8f9fa] min-h-screen py-8 md:py-10 font-sans relative">

      {/* ========================================================
          🚀 THE EXACT CENTERED MODAL (From Last Image)
          ======================================================== */}
      {showModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-gray-900/40 backdrop-blur-sm transition-all duration-300">
          <div className="bg-white rounded-[24px] shadow-2xl w-full max-w-sm p-8 transform transition-all flex flex-col items-center text-center animate-in zoom-in-95 duration-200">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mb-5">
              <AlertTriangle size={28} strokeWidth={1.5} />
            </div>
            <h3 className="text-[20px] font-bold text-gray-900 mb-2 tracking-tight">Missing Information</h3>
            <p className="text-[14px] text-gray-500 mb-8 leading-relaxed px-2">
              {modalMessage}
            </p>
            <button
              onClick={() => setShowModal(false)}
              className="w-full bg-[#0f172a] text-white font-bold py-3.5 rounded-xl hover:bg-gray-800 transition-colors outline-none focus:outline-none"
            >
              GOT IT
            </button>
          </div>
        </div>
      )}

      <div className="container mx-auto px-4 max-w-6xl">
        <div className="mb-6">
          <button
            onClick={() => navigate('/cart')}
            className="inline-flex items-center text-sm font-bold text-orange-500 hover:text-orange-600 transition-colors group outline-none focus:outline-none focus:ring-0 border-none bg-transparent select-none"
            style={{ WebkitTapHighlightColor: 'transparent' }}
          >
            <ChevronLeft size={18} className="group-hover:-translate-x-1 transition-transform" />
            Return to Cart
          </button>
        </div>

        <div className="flex items-center mb-6">
          <h1 className="text-[28px] font-black text-gray-900 tracking-tight">Checkout</h1>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">

          {/* LEFT COLUMN: FORMS */}
          <div className="lg:col-span-7 flex flex-col gap-6">

            {/* SHIPPING ADDRESS */}
            <div className="bg-white rounded-3xl shadow-sm border border-gray-100 p-6 md:p-8">
              <div className="flex items-center gap-3 mb-8">
                <div className="bg-[#6f4f36] text-white p-2 rounded-full">
                  <MapPin size={20} strokeWidth={2} />
                </div>
                <h2 className="text-lg font-bold text-gray-900">Shipping Address</h2>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-x-5 gap-y-6">
                <div className="relative md:col-span-1">
                  <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">Full Name <span className="text-red-500">*</span></label>
                  <input type="text" name="fullName" value={shipping.fullName} onChange={handleShippingChange} className={getInputClass(errors.shipping_fullName)} placeholder="e.g. John Doe" />
                </div>

                <div className="relative md:col-span-1">
                  <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">Phone Number <span className="text-red-500">*</span></label>
                  <input type="tel" name="phone" value={shipping.phone} onChange={handleShippingChange} maxLength="10" className={getInputClass(errors.shipping_phone)} placeholder="e.g. 9876543210" />
                </div>

                <div className="relative md:col-span-2">
                  <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">Address Line 1 <span className="text-red-500">*</span></label>
                  <input type="text" name="address1" value={shipping.address1} onChange={handleShippingChange} className={getInputClass(errors.shipping_address1)} placeholder="House No., Building Name, Street" />
                </div>

                <div className="relative md:col-span-2">
                  <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">Address Line 2 (Optional)</label>
                  <input type="text" name="address2" value={shipping.address2} onChange={handleShippingChange} className={getInputClass(false)} placeholder="Locality, Area, Landmark" />
                </div>

                <div className="md:col-span-2 grid grid-cols-1 sm:grid-cols-3 gap-4 md:gap-5">
                  <div className="relative">
                    <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">City <span className="text-red-500">*</span></label>
                    <input type="text" name="city" value={shipping.city} onChange={handleShippingChange} className={getInputClass(errors.shipping_city)} placeholder="City" />
                  </div>

                  <div className="relative">
                    <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">State <span className="text-red-500">*</span></label>
                    <input type="text" name="state" value={shipping.state} onChange={handleShippingChange} className={getInputClass(errors.shipping_state)} placeholder="State" />
                  </div>

                  <div className="relative">
                    <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">Pincode <span className="text-red-500">*</span></label>
                    <div className="relative">
                      <input type="text" name="pincode" value={shipping.pincode} onChange={handleShippingChange} maxLength="6" className={getInputClass(errors.shipping_pincode)} placeholder="500001" />
                      {fetchingPin.shipping && <div className="absolute right-3 top-1/2 -translate-y-1/2"><Loader2 size={18} className="text-orange-500 animate-spin" /></div>}
                    </div>
                  </div>
                </div>
              </div>

              <div className="mt-8 pt-6 flex md:justify-start">
                <button
                  onClick={handleContinuePayment}
                  className="w-full md:w-auto bg-[#6f4f36] text-white px-10 py-3.5 rounded-xl font-bold tracking-wide hover:bg-[#543b28] active:scale-[0.98] transition-all duration-300 outline-none focus:outline-none focus:ring-0 select-none border-none text-[15px]"
                >
                  Continue to Payment
                </button>
              </div>
            </div>

            {/* ========================================================
                BILLING TOGGLE BOX (Exact match to Image 2)
                ======================================================== */}
            <div
              className="bg-white rounded-[20px] shadow-sm border border-gray-100 p-5 flex items-center gap-3 cursor-pointer select-none"
              onClick={() => setIsBillingSame(!isBillingSame)}
            >
              <div className={`w-[22px] h-[22px] flex items-center justify-center rounded transition-colors ${isBillingSame ? 'bg-[#f97316]' : 'bg-gray-50 border border-gray-300'}`}>
                {isBillingSame && (
                  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round">
                    <polyline points="20 6 9 17 4 12"></polyline>
                  </svg>
                )}
              </div>
              <span className="text-[16px] text-gray-800 tracking-tight">Billing address is same as the Shipping address</span>
            </div>

          </div>

          {/* ========================================================
              RIGHT COLUMN: ORDER SUMMARY (Exact match to Cart Image 1)
              ======================================================== */}
          <div className="lg:col-span-5 flex flex-col gap-6 md:sticky md:top-28">
            <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">

              <div className="p-6 pb-4 border-b border-gray-100">
                <h3 className="text-lg font-bold text-gray-900 mb-5">Order Summary</h3>
                <div className="flex flex-col gap-4 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
                  {validItems.map((item, index) => {
                    return (
                      <div key={index} className="flex items-start gap-4">
                        <div className="w-[72px] h-[72px] bg-gray-50 rounded-xl overflow-hidden border border-gray-100 shrink-0">
                          <img src={item.image || 'https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=200&q=80'} alt={item.name} className="w-full h-full object-cover" onError={(e) => { e.target.onerror = null; e.target.src = 'https://images.unsplash.com/photo-1493663284031-b7e3aefcae8e?w=200&q=80'; }} />
                        </div>
                        <div className="flex-1 min-w-0 pt-1">
                          <h4 className="text-[14px] text-gray-800 leading-snug">{item.name || 'Premium Item'}</h4>
                          <p className="text-[12px] font-bold text-gray-500 mt-2">Quantity : {Number(item.quantity) || 1}</p>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>

              {/* Price Detail Section */}
              <div className="p-6">
                <h3 className="text-[16px] font-semibold text-gray-800 mb-5">Price Detail <span className="font-normal text-gray-500 text-[14px]">({totalItems} Items)</span></h3>

                <div className="space-y-4">
                  <div className="flex justify-between items-center text-[14px] font-bold">
                    <span className="text-gray-800">MRP</span>
                    <span className="text-gray-900">₹{totalMrp.toLocaleString('en-IN')}</span>
                  </div>

                  {baseDiscount > 0 && (
                    <div className="flex justify-between items-center text-[14px] font-bold">
                      <span className="text-gray-800">Discount</span>
                      <span className="text-[#22c55e]">- ₹{baseDiscount.toLocaleString('en-IN')}</span>
                    </div>
                  )}

                  <div className="flex justify-between items-center text-[14px] font-bold">
                    <span className="text-gray-800">Shipping</span>
                    <span className="text-[#22c55e]">Free</span>
                  </div>

                  <div className="flex justify-between items-center text-[14px] font-bold">
                    <span className="text-gray-800">GST (18%)</span>
                    <span className="text-gray-900">₹{gst.toLocaleString('en-IN')}</span>
                  </div>
                </div>

                <div className="mt-5 pt-5 border-t border-gray-200 border-dashed">
                  <div className="flex justify-between items-start">
                    <span className="text-[18px] text-gray-800">Total Payable</span>
                    <div className="text-right">
                      <span className="text-[20px] font-bold text-gray-900 leading-none block mb-1">₹{finalPayable.toLocaleString('en-IN')}</span>
                      <span className="text-[11px] text-gray-500">Inclusive of all taxes</span>
                    </div>
                  </div>
                </div>
              </div>

              {/* Congratulations Savings Box */}
              {baseDiscount > 0 && (
                <div className="p-4 bg-[#f0fdf4] border-t border-[#bbf7d0]">
                  <p className="text-[13px] font-medium text-[#166534] text-center leading-relaxed">
                    Congratulations! You've Just saved ₹{baseDiscount.toLocaleString('en-IN')} On Your Order.
                  </p>
                </div>
              )}

            </div>
          </div>

        </div>
      </div>

      <style jsx="true">{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e5e7eb; border-radius: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #d1d5db; }
      `}</style>
    </div>
  );
};

export default CheckoutPage;
